const products = items.map(item => item.json);

const chatId = $('Compose Context').first().json.chatId;
const categoryName = $('Order Menu Switch').first().json.name;

let menu = `📕 Cardápio de ${categoryName}\n\n`;

let counter = 1;

let optionsMap = {};

for (const product of products) {

  if (!product.active) continue;

  menu += `[ ${counter} ] - ${product.name} (R$ ${product.price})\n`;

  optionsMap[counter] = {
    type: "select_product",
    productId: product.id,
    name: product.name,
    price: product.price
  };

  counter++;
}

menu += `[ ${counter} ] - Voltar\n`;

optionsMap[counter] = {
  type: "back_to_order_menu"
};

menu += "\nDigite o número da opção desejada.";

return [{
  json: {
    chatId,
    menu,
    optionsMap
  }
}];

return [{
