const categories = items.map(item => item.json);
const chatId = $json.chatId;

let menu = "🛒 Seu Pedido\n\n";
menu += "O que você gostaria de fazer agora?\n\n";

let counter = 1;
let optionsMap = {};

for (const category of categories) {
  menu += `[ ${counter} ] - Adicionar ${category.name}\n`;

  optionsMap[counter] = {
    type: "select_category",
    categoryId: category.id,
    name: category.name
  };

  counter++;
}

menu += `[ ${counter} ] - Voltar ao menu principal\n`;
optionsMap[counter] = { type: "menu" };
counter++;

menu += `[ ${counter} ] - Finalizar Pedido\n`;
optionsMap[counter] = { type: "checkout" };

menu += "\nDigite o número da opção desejada.";

return [{
  json: {
    chatId,
    menu,
    optionsMap
  }
}];

const chatId = $json.chatId;
const text = $json.input.text;

const number = Number(text);
const optionsMap = $json.user.data?.optionsMap;

if (!optionsMap) {
  return [{
    json: {
      chatId,
      error: "no_options_map"
    }
  }];
}

const option = optionsMap[number];

if (!option) {
  return [{
    json: {
      chatId,
      type: "invalid"
    }
  }];
}

return [{
  json: {
    chatId,
    type: option.type,
    categoryId: option.categoryId,
    name: option.name
  }
}];

