const orderId = $('Webhook').first().json.body.order_id;
const status = $('Webhook').first().json.body.status;
const user = $json;

let message = "";

switch (status) {
  case "pedido_recebido":
    message = `🧾 Pedido #${orderId} recebido com sucesso!\nEstamos organizando tudo para você.`;
    break;

  case "em_preparo":
    message = `👨‍🍳 Pedido #${orderId} está em preparo!\nLogo logo sai quentinho 🍕`;
    break;

  case "a_caminho":
    message = `🛵 Pedido #${orderId} saiu para entrega!\nFique atento 😉`;
    break;

  case "finalizado":
    message = `✅ Pedido #${orderId} foi finalizado!\nObrigado por pedir com a gente 💚`;
    break;

  case "cancelado":
    message = `❌ Pedido #${orderId} foi cancelado.\nSe precisar, estamos aqui.`;
    break;

  default:
    message = `📦 Pedido #${orderId} atualizado para: ${status}`;
}

return [
  {
    json: {
      chat_id: user.telegram_chat_id,
      text: message
    }
  }
];

