const order = items[0].json;

function formatStatus(status) {
  const map = {
    carrinho: "🛒 No carrinho",
    pedido_recebido: "📩 Pedido recebido",
    em_preparo: "👨‍🍳 Em preparo",
    a_caminho: "🚚 A caminho",
    finalizado: "✅ Finalizado",
    cancelado: "❌ Cancelado"
  };

  return map[status] || status;
}

let message = `🧾 Resumo do seu pedido #${order.order_number}\n`;
message += `📌 Status: ${formatStatus(order.status)}\n\n`;

for (const item of order.items) {
  message += `• ${item.quantity}x ${item.name} - R$ ${item.total_price.toFixed(2)}\n`;
}

message += `\n💰 Total: R$ ${order.total_price.toFixed(2)}`;

if (order.payment) {
  message += `\n💳 Pagamento: ${order.payment}`;
}

if (order.address) {
  message += `\n📍 Entrega: ${order.address}`;
}

if (order.observation) {
  message += `\n📝 Obs: ${order.observation}`;
}

return [
  {
    json: {
      message
    }
  }
];

